'use client'

import { useRef, useState, useCallback, useEffect, ReactNode } from 'react'

interface FloatingPanelProps {
  title: string
  accentColor: string
  defaultX?: number
  defaultY?: number
  width?: number
  children: ReactNode
  onClose?: () => void
}

export default function FloatingPanel({
  title,
  accentColor,
  defaultX = 20,
  defaultY = 80,
  width = 180,
  children,
  onClose,
}: FloatingPanelProps) {
  const [pos, setPos] = useState({ x: defaultX, y: defaultY })
  const [isDragging, setIsDragging] = useState(false)
  const dragRef = useRef<{ startX: number; startY: number; origX: number; origY: number } | null>(null)
  const activeDragRef = useRef<{ onMouseMove: (e: MouseEvent) => void; onMouseUp: () => void } | null>(null)

  const onMouseDown = useCallback((e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('.close-btn')) return
    e.preventDefault()
    setIsDragging(true)
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      origX: pos.x,
      origY: pos.y,
    }
    const onMouseMove = (me: MouseEvent) => {
      if (!dragRef.current) return
      const dx = me.clientX - dragRef.current.startX
      const dy = me.clientY - dragRef.current.startY
      setPos({
        x: dragRef.current.origX + dx,
        y: dragRef.current.origY + dy,
      })
    }
    const onMouseUp = () => {
      setIsDragging(false)
      dragRef.current = null
      activeDragRef.current = null
      window.removeEventListener('mousemove', onMouseMove)
      window.removeEventListener('mouseup', onMouseUp)
    }
    activeDragRef.current = { onMouseMove, onMouseUp }
    window.addEventListener('mousemove', onMouseMove)
    window.addEventListener('mouseup', onMouseUp)
  }, [])

  useEffect(() => {
    return () => {
      if (activeDragRef.current) {
        window.removeEventListener('mousemove', activeDragRef.current.onMouseMove)
        window.removeEventListener('mouseup', activeDragRef.current.onMouseUp)
        activeDragRef.current = null
      }
    }
  }, [])

  return (
    <div
      className={`floating-panel ${isDragging ? 'dragging' : ''}`}
      style={{
        left: pos.x,
        top: pos.y,
        width,
        '--accent-color': accentColor,
        zIndex: isDragging ? 150 : 100,
      } as React.CSSProperties}
    >
      <div
        className="title-bar"
        onMouseDown={onMouseDown}
      >
        <span>{title}</span>
        {onClose && (
          <div
            className="close-btn"
            onClick={onClose}
            style={{ color: accentColor }}
          >
            ×
          </div>
        )}
      </div>
      <div className="panel-body" style={{ color: 'rgba(255,255,255,0.7)', fontSize: '12px' }}>
        {children}
      </div>
    </div>
  )
}